using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator = new();

    // --- CalculateTotal: DataRow for simple inline cases ---

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 2, 0.0, 20.00, DisplayName = "Two items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.00, 4, 0.20, 120.00, DisplayName = "Multiple items, 20% tax")]
    [DataRow(0.00, 5, 0.10, 0.00, DisplayName = "Zero price")]
    [DataRow(99.99, 0, 0.15, 0.00, DisplayName = "Zero quantity")]
    public void CalculateTotal_WithValidInputs_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // --- CalculateTotal: DynamicData with ValueTuples for richer cases ---

    [TestMethod]
    [DynamicData(nameof(CalculateTotalEdgeCases))]
    public void CalculateTotal_EdgeCases_ReturnsExpected(
        decimal unitPrice, int quantity, decimal taxRate, decimal expected)
    {
        var result = _calculator.CalculateTotal(unitPrice, quantity, taxRate);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal unitPrice, int quantity, decimal taxRate, decimal expected)> CalculateTotalEdgeCases =>
    [
        (0.01m, 1, 0m, 0.01m),          // Smallest meaningful price
        (9999.99m, 100, 0.25m, 1249998.75m), // Large order with tax
        (50m, 3, 1m, 300m),              // Maximum tax rate (100%)
        (100m, 1, 0m, 100m),            // No tax boundary
    ];

    // --- CalculateTotal: invalid inputs throw ---

    [TestMethod]
    public void CalculateTotal_NegativeQuantity_Throws()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(10m, -1, 0.1m));

        Assert.AreEqual("quantity", ex.ParamName);
    }

    [TestMethod]
    public void CalculateTotal_NegativeUnitPrice_Throws()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(-5m, 1, 0.1m));

        Assert.AreEqual("unitPrice", ex.ParamName);
    }

    [TestMethod]
    [DataRow(-0.01, DisplayName = "Tax rate below 0")]
    [DataRow(1.01, DisplayName = "Tax rate above 1")]
    public void CalculateTotal_InvalidTaxRate_Throws(double taxRate)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(10m, 1, (decimal)taxRate));

        Assert.AreEqual("taxRate", ex.ParamName);
    }

    // --- ApplyDiscount: DataRow ---

    [TestMethod]
    [DataRow(100.00, 0.0, 100.00, DisplayName = "No discount")]
    [DataRow(100.00, 10.0, 90.00, DisplayName = "10% off")]
    [DataRow(100.00, 50.0, 50.00, DisplayName = "50% off")]
    [DataRow(100.00, 100.0, 0.00, DisplayName = "100% off (free)")]
    [DataRow(200.00, 25.0, 150.00, DisplayName = "25% off $200")]
    public void ApplyDiscount_WithValidInputs_ReturnsExpected(
        double price, double discountPercent, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent);

        Assert.AreEqual((decimal)expected, result);
    }

    // --- ApplyDiscount: DynamicData with ValueTuples ---

    [TestMethod]
    [DynamicData(nameof(ApplyDiscountEdgeCases))]
    public void ApplyDiscount_EdgeCases_ReturnsExpected(
        decimal price, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal price, decimal discountPercent, decimal expected)> ApplyDiscountEdgeCases =>
    [
        (0m, 50m, 0m),                  // Zero price with discount
        (0.01m, 50m, 0.005m),           // Smallest price
        (999.99m, 33.33m, 666.653367m), // Non-round discount
    ];

    // --- ApplyDiscount: invalid inputs throw ---

    [TestMethod]
    [DataRow(-1.0, DisplayName = "Discount below 0")]
    [DataRow(100.01, DisplayName = "Discount above 100")]
    public void ApplyDiscount_InvalidDiscountPercent_Throws(double discountPercent)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, (decimal)discountPercent));
    }

    // --- FormatPrice ---

    [TestMethod]
    [DataRow(19.99, "$", "$19.99", DisplayName = "Default USD")]
    [DataRow(19.99, "€", "€19.99", DisplayName = "Euro symbol")]
    [DataRow(0.00, "$", "$0.00", DisplayName = "Zero price")]
    [DataRow(1234.5, "$", "$1234.50", DisplayName = "Pads to 2 decimals")]
    public void FormatPrice_WithSymbol_ReturnsFormattedString(
        double price, string symbol, string expected)
    {
        var result = _calculator.FormatPrice((decimal)price, symbol);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void FormatPrice_DefaultSymbol_UsesDollarSign()
    {
        var result = _calculator.FormatPrice(42.10m);

        Assert.StartsWith("$", result);
        Assert.AreEqual("$42.10", result);
    }
}

